const DEDUCTIBLE_PER_DAMAGE = 100;

export function claim(_items: Item[], incident: Incident): number {
  const total = incident.damages.reduce(
    (sum, damage) => sum + (damage.amount - DEDUCTIBLE_PER_DAMAGE),
    0,
  );
  return Math.floor(total);
}
